import { useState } from 'react'
import { db } from '../../db/db.js'

export default function Watchlist({ videos, onClose, onOpen }) {
  const [query, setQuery] = useState(''), [tab, setTab] = useState('active')
  const filtered = videos.filter(video => video.status === tab && [video.title, video.customLabel, video.channelName, ...(video.tags || [])].join(' ').toLowerCase().includes(query.toLowerCase()))
  return <div className="overlay" onMouseDown={event => event.target === event.currentTarget && onClose()}><section className="modal watchlist"><header><div><span className="eyebrow">LOCAL LIBRARY</span><h2>Watchlist</h2></div><button className="plain close" onClick={onClose}>ESC</button></header><div className="watch-controls"><div className="segmented"><button className={tab === 'active' ? 'active' : ''} onClick={() => setTab('active')}>ACTIVE</button><button className={tab === 'archived' ? 'active' : ''} onClick={() => setTab('archived')}>ARCHIVED</button></div><input value={query} onChange={event => setQuery(event.target.value)} placeholder="Search title, channel, tag" /></div><div className="watch-rows">{filtered.map(video => <div key={video.videoId}>{video.thumbnailUrl ? <img src={video.thumbnailUrl} alt="" /> : <div className="thumb-placeholder" />}<button className="row-main" onClick={() => onOpen(video)}><b>{video.customLabel || video.title}</b><span>{video.channelName} · {video.lastViewCount?.toLocaleString() || 'No samples'}</span></button><button onClick={() => db.videos.update(video.id, { status: tab === 'active' ? 'archived' : 'active' })}>{tab === 'active' ? 'ARCHIVE' : 'ACTIVATE'}</button><button className="danger-button" onClick={() => confirm('Remove this video and all local history?') && db.transaction('rw', db.videos, db.datapoints, db.notes, db.milestones, async () => { await db.videos.delete(video.id); await db.datapoints.where('videoId').equals(video.videoId).delete(); await db.notes.where('videoId').equals(video.videoId).delete(); await db.milestones.where('videoId').equals(video.videoId).delete() })}>REMOVE</button></div>)}</div></section></div>
}
